changeSet.sql:
ALTER TABLE feedback DROP CONSTRAINT chk_feedback_suppression_reason;
UPDATE feedback SET suppression_reason = 'VOLUME_CAPPED' WHERE suppression_reason = 'POLICY_FLOOR_DROP';
ALTER TABLE feedback ADD CONSTRAINT chk_feedback_suppression_reason CHECK (suppression_reason IS NULL OR suppression_reason IN ('VOLUME_CAPPED', 'COMPOSER_DEDUPED', 'REACTED_DISPUTED', 'REACTED_NOT_APPLICABLE', 'CONVERSATION_EXPIRED', 'ARTIFACT_GONE', 'ARTIFACT_CLOSED', 'ARTIFACT_MERGED', 'ARTIFACT_DRAFT', 'RECIPIENT_OPTED_OUT', 'EMPTY_AFTER_SANITIZE'));

rollback.sql:
ALTER TABLE feedback DROP CONSTRAINT chk_feedback_suppression_reason;
UPDATE feedback SET suppression_reason = 'POLICY_FLOOR_DROP' WHERE suppression_reason = 'VOLUME_CAPPED';
-- Reasons the restored code cannot express. NULL (permitted by the restored CHECK) keeps the
-- rollback executable and stays honest: the row was withheld, for a reason this schema lost.
UPDATE feedback SET suppression_reason = NULL WHERE suppression_reason IN ('COMPOSER_DEDUPED', 'ARTIFACT_GONE', 'ARTIFACT_CLOSED', 'ARTIFACT_MERGED', 'ARTIFACT_DRAFT', 'RECIPIENT_OPTED_OUT', 'EMPTY_AFTER_SANITIZE');
ALTER TABLE feedback ADD CONSTRAINT chk_feedback_suppression_reason CHECK (suppression_reason IS NULL OR suppression_reason IN ('REVIEWER_SIDE', 'BELOW_THRESHOLD', 'LOW_CONFIDENCE', 'POLICY_FLOOR_DROP', 'REACTED_DISPUTED', 'REACTED_NOT_APPLICABLE', 'CONVERSATION_EXPIRED'));
